        "vilagterkep_h1_1": "<strong>Карта Абриго</strong>",
        "vilagterkep_h3_2": "Горы Драконьего хребта",
        "vilagterkep_h3_3": "Сердце Арии",
        "vilagterkep_h3_4": "Штормовой портал",
        "vilagterkep_h3_5": "Бассейн Катаракбис",
        "vilagterkep_h3_6": "Острова Йогга",
        "vilagterkep_h3_7": "Буквенное море",
        "vilagterkep_h3_8": "Дельта региона",
        "vilagterkep_h3_9": "Шепчущие фьорды",
        "vilagterkep_h3_10": "Империя острова Агавы",
        "vilagterkep_h3_11": "Защитный лес",
        "vilagterkep_h3_12": "Холмы королей",
        "vilagterkep_h3_13": "Самолет восточных королей",
